var e=[{id:`L2_1`,type:`dialog`,speaker:`JOHN_MASON_NULL_NULL`,text:{KOREA:` 좋아, 찾기는 찾았는데…….`,JPN:` よし、見つけはしたが……`,ENG:`Okay. We found them, but...`,TWN:`很好，找是找到了……`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JOHN_MASON_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`SYLVIA_DELTA_NULL_NULL`,text:{KOREA:` 숫자가 어마어마하네. 왜 신호가 안 잡혔는지 알겠어.`,JPN:` とんでもない数ね。なんで信号を捕まえられなかったのか納得だわ。`,ENG:`That's a lot of C.O.s. No wonder the signal wasn't coming in.`,TWN:`數量太多了。我知道為什麼沒捕捉到訊號了。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`SYLVIA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:`JAINA_DELTA_NULL_NULL`,text:{KOREA:` 허수공간에는 아무것도 없는 것 아니었나요? 어떻게 이렇게 많은 침식체가 있는 거죠?`,JPN:` 虚数空間には何もないはずでは？　なぜここまでたくさんの侵食体がいるんでしょうか？`,ENG:`Isn't the imaginary space supposed to be empty? Why are there so many C.O.s?`,TWN:`虛數空間不是什麼都沒有嗎？怎麼會有這麼多侵蝕體？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JAINA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:` 그건 오해예요. `,JPN:` それは誤解です。 `,ENG:`That's a misconception.`,TWN:`那是個誤會。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JAINA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:` 여러분은 이미 허신과 마주쳐 보셨잖아요?`,JPN:` みなさんはすでに虚神に会っていますよね？`,ENG:`You all have already seen the Hollow God.`,TWN:`大家已經見過幻神了不是嘛？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JAINA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L8_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:` 기억해 두세요. 이 세상 전부, 인류에 대한 무심한 악의로 왜곡되어 있다는 걸.`,JPN:` 覚えておいてください。この世界のすべてが、人類に対する何気ない悪意によって捻じ曲げられているということを。`,ENG:`Remember. Everything in this world is distorted with cold malice towards humanity.`,TWN:`記住，這個世界的一切，都被扭曲成了下意識地對人類充滿惡意。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JAINA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L9_1`,type:`dialog`,speaker:`JAINA_DELTA_NULL_NULL`,text:{KOREA:` 회장님의 말씀대로라면…….`,JPN:` 会長のお言葉通りであれば……`,ENG:`If that’s the case...`,TWN:`按照會長所說的……`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JAINA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L12_1`,type:`dialog`,speaker:`JAINA_DELTA_NULL_NULL`,text:{KOREA:` ……그 남자는 역시, 무사할 리 없겠군요.`,JPN:` ……あの男も当然、無事であるはずがありませんね。`,ENG:`...He wouldn’t be safe and sound.`,TWN:`……那個男人，會平安無事嗎……`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JAINA_DELTA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`JAKE_DELTA_NEXT_NULL`,text:{KOREA:` 소령, 지금은 다른 데 한눈 팔지 말도록.`,JPN:` 少佐、今はここの問題に集中しろ。`,ENG:`Do not get distracted, Major.`,TWN:`少校，現在不要管別的事。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JAKE_DELTA_NEXT_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`JAINA_DELTA_NULL_NULL`,text:{KOREA:` 아. 죄송합니다, 대령님….`,JPN:` あ、すみません、大佐……`,ENG:`Oh. My apologies, Colonel...`,TWN:`啊，對不起，上校……`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JAINA_DELTA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`JAKE_DELTA_NEXT_NULL`,text:{KOREA:` 자. 엔지니어들은 함교에서 구경하고 있으라고.`,JPN:` さて、エンジニアのみんなは艦橋でよく見ていてくれ。`,ENG:`Now. Engineers, you guys sit back and watch at the bridge.`,TWN:`好了，讓工程師們在艦橋上看著。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JAKE_DELTA_NEXT_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`JAKE_DELTA_NEXT_NULL`,text:{KOREA:` 세상이 우리에게 그렇게 악의적이라면 가르쳐 줘야지.`,JPN:` 世界が俺たちにそこまで悪意を向けているなら教えてやらないとな。`,ENG:`If the world really is so malicious towards us, we should teach them a lesson.`,TWN:`如果世界果真對我們充滿惡意，那就應該告訴它。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JAKE_DELTA_NEXT_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`JAKE_DELTA_NEXT_NULL`,text:{KOREA:` 오늘은…… 상대를 잘못 만났다는 걸 말이야. `,JPN:` 今日は……悪意を向ける相手を間違えたとな。 `,ENG:`A lesson... that they're messing with the wrong people.`,TWN:`今天……它找錯對象了。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`JAKE_DELTA_NEXT_NULL`,face:`UNIT_PRIDE`},C:null,R:null}}}];export{e as default};